#include "TriggerOnOff.h"
#include "FL_TriggerJson.h"
namespace FLTriggers { TriggerOnOff::TriggerOnOff():activateTarget_(false),deactivateTarget_(false),pauseTarget_(false),resumeTarget_(false),sleepTarget_(false),wakeTarget_(false),switchStateOnly_(false){callOnlyOnce_=false;}void TriggerOnOff::load(const std::string&i,const flrapidjson::Value&j){Trigger::load(i,j);activateTarget_=Json::boolean(j,"activateTarget");deactivateTarget_=Json::boolean(j,"deactivateTarget");pauseTarget_=Json::boolean(j,"pauseTarget");resumeTarget_=Json::boolean(j,"resumeTarget");sleepTarget_=Json::boolean(j,"sleepTarget");wakeTarget_=Json::boolean(j,"wakeTarget");switchStateOnly_=Json::boolean(j,"switchStateOnly");}void TriggerOnOff::activateTrigger(TriggerSystem&s,FL_TriggerHost&h){if(cooldownRemaining_>0)return;GroupCallType t=activateTarget_?GroupActivate:deactivateTarget_?GroupDeactivate:resumeTarget_?GroupResume:pauseTarget_?GroupPause:GroupSwitchState;if(switchStateOnly_)t=GroupSwitchState;s.activateGroup(callGroupID_,t,wakeTarget_,sleepTarget_,h);cooldownRemaining_=1;}}
